"""Generator: start.py — 統一入口。"""
from pathlib import Path

CONTENT = '"""Ark Agent Platform — 統一入口。\n\n啟動全部服務：Backend API + Telegram Bot + Agent Daemon + EventBus + Scheduler\n"""\nfrom __future__ import annotations\n\nimport asyncio\nimport logging\nimport os\nimport sys\nimport time\nfrom pathlib import Path\n\nsys.path.insert(0, str(Path(__file__).resolve().parent / "src"))\n\nfrom dotenv import load_dotenv\nload_dotenv()\n\n\nasync def main() -> None:\n    # Logging\n    log_dir = Path("logs")\n    log_dir.mkdir(exist_ok=True)\n    fmt = "%(asctime)s [%(name)s] %(levelname)s %(message)s"\n    logging.basicConfig(\n        level=logging.INFO,\n        format=fmt,\n        handlers=[\n            logging.FileHandler(log_dir / "platform.log", encoding="utf-8"),\n            logging.StreamHandler(),\n        ],\n    )\n    logging.getLogger("httpx").setLevel(logging.WARNING)\n    logging.getLogger("uvicorn").setLevel(logging.WARNING)\n    log = logging.getLogger("platform")\n\n    # ── 1. DB + EventBus ──\n    from backend.db.models import init_db, get_db, fetch_one, insert, now_iso\n    from backend.events.bus import EventBus\n    from backend.events.types import EventType, Event\n    from backend.services.cost_tracker import on_agent_output\n    from backend.services.audit_logger import on_any_event\n\n    init_db()\n\n    # Sync team.yaml agents → DB\n    from ark_team_core.config import load_config as _lc\n    _tc = _lc("team.yaml")\n    _conn = get_db()\n    for _name, _ic in _tc.instances.items():\n        existing = fetch_one(_conn, "SELECT id FROM agents WHERE id=?", (_name,))\n        if not existing:\n            insert(_conn, "agents", {\n                "id": _name, "name": _name, "role": _ic.role,\n                "provider": "kiro-cli", "working_dir": _ic.working_directory,\n                "model": _ic.model or \'auto\',\n                "status": "idle", "created_at": now_iso(), "updated_at": now_iso(),\n            })\n    _conn.close()\n\n    bus = EventBus()\n    bus.subscribe(EventType.AGENT_OUTPUT, on_agent_output)\n    for et in EventType:\n        bus.subscribe(et, on_any_event)\n    await bus.start()\n    log.info("DB + EventBus 已啟動")\n\n    # ── 2. Backend API ──\n    import uvicorn\n    from backend.api.router import app\n    app.state.bus = bus\n    app.state._external_bus = True\n\n    api_port = int(os.environ.get("API_PORT", "33333"))\n    config = uvicorn.Config(app, host="127.0.0.1", port=api_port, log_level="warning")\n    server = uvicorn.Server(config)\n    api_task = asyncio.create_task(server.serve())\n    await asyncio.sleep(1)\n    log.info("Backend API 已啟動 (port %d)", api_port)\n\n    # ── 3. Agent Daemon ──\n    from ark_team_core.config import load_config\n    from ark_team_core.process import AgentProcess\n\n    team_config = load_config("team.yaml")\n    agents: dict[str, AgentProcess] = {}\n\n    # TG reply callback（稍後設定）\n    tg_reply_fn = None\n    _tg_handled_agents: set[str] = set()  # agents currently handled by TG handler directly\n\n    import re\n    _ANSI_RE = re.compile(r"\\x1b\\[[0-9;]*m|\\x1b\\[\\?[0-9]*[hl]|\\x1b\\[[0-9]*[A-Z]")\n\n    def _clean_output(text: str) -> str:\n        """Strip ANSI codes + kiro-cli prompt markers."""\n        text = _ANSI_RE.sub("", text)\n        # Remove leading \'> \' prompt marker per line\n        lines = [l.lstrip("> ") if l.startswith("> ") else l for l in text.splitlines()]\n        return "\\n".join(lines).strip()\n\n    async def _on_agent_output(agent_name: str, text: str):\n        text = _clean_output(text)\n        if not text:\n            return\n        # 記錄 session\n        import uuid\n        from backend.db.models import get_db, insert, now_iso\n        conn = get_db()\n        try:\n            insert(conn, "agent_sessions", {\n                "id": str(uuid.uuid4())[:8],\n                "agent_id": agent_name,\n                "status": "completed",\n                "started_at": now_iso(),\n                "ended_at": now_iso(),\n                "total_tokens": len(text) // 4,\n                "cost_usd": len(text) * 0.003 / 1000 * 4,\n                "output": text[:2000],\n            })\n        except Exception:\n            pass\n        if tg_reply_fn and agent_name not in _tg_handled_agents:\n            await tg_reply_fn(agent_name, text)\n\n    log.info("啟動 %d agents...", len(team_config.instances))\n    for name, ic in team_config.instances.items():\n        proc = AgentProcess(\n            name=name, working_dir=ic.working_directory,\n            model=ic.model, skip_resume=ic.skip_resume,\n        )\n        proc.on_output = _on_agent_output\n        proc.event_bus = bus\n        agents[name] = proc\n        await proc.start()\n        await asyncio.sleep(1)\n    log.info("所有 agents 已就緒 (%d)", len(agents))\n\n    # ── 3b. Task Dispatcher — TASK_ASSIGNED → agent.send() ──\n    async def _on_task_assigned(event: Event):\n        """Issue 被指派後，觸發對應 agent 執行。"""\n        data = event.data\n        assignee = data.get("assignee", "")\n        issue_id = data.get("issue_id", "")\n        agent = agents.get(assignee)\n        if not agent:\n            log.warning("Task %s assigned to unknown agent: %s", issue_id, assignee)\n            return\n        # 取 issue title 作為 prompt\n        conn = get_db()\n        issue = fetch_one(conn, "SELECT title, description FROM issues WHERE id=?", (issue_id,))\n        if not issue:\n            return\n        prompt = issue["title"]\n        if issue.get("description"):\n            prompt += f"\\n\\n{issue[\'description\']}"\n        log.info("Dispatching issue %s to %s: %s", issue_id, assignee, prompt[:60])\n        result = await agent.send(prompt)\n        # 更新 issue 狀態\n        status = "completed" if result else "failed"\n        conn.execute(\n            "UPDATE issues SET status=?, completed_at=?, updated_at=? WHERE id=?",\n            (status, now_iso(), now_iso(), issue_id))\n        conn.commit()\n\n    bus.subscribe(EventType.TASK_ASSIGNED, _on_task_assigned)\n\n    # ── 4. Telegram Bot ──\n    tg_app = None\n    notify_service = None\n    token = os.environ.get("TELEGRAM_BOT_TOKEN", "")\n    if token:\n        from telegram.ext import ApplicationBuilder, CommandHandler, MessageHandler, CallbackQueryHandler, filters\n        from telegram import BotCommand\n\n        tg_app = ApplicationBuilder().token(token).build()\n        tg_app.bot_data["api_base"] = f"http://127.0.0.1:{api_port}"\n        tg_app.bot_data["agents"] = agents\n        tg_app.bot_data["handled_agents"] = _tg_handled_agents\n\n        # 註冊 handlers\n        from tg_ui.handlers.commands import (\n            cmd_start, cmd_status, cmd_agents, cmd_board, cmd_costs,\n            cmd_queue, cmd_assign, cmd_stop, cmd_retry, cmd_logs, cmd_help,\n        )\n        from tg_ui.handlers.callbacks import handle_callback\n        from tg_ui.handlers.messages import handle_message\n\n        for name_cmd, fn in [\n            ("start", cmd_start), ("status", cmd_status), ("agents", cmd_agents),\n            ("board", cmd_board), ("costs", cmd_costs), ("queue", cmd_queue),\n            ("assign", cmd_assign), ("stop", cmd_stop), ("retry", cmd_retry),\n            ("logs", cmd_logs), ("help", cmd_help),\n        ]:\n            tg_app.add_handler(CommandHandler(name_cmd, fn))\n        tg_app.add_handler(CallbackQueryHandler(handle_callback))\n        tg_app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, handle_message))\n\n        async def _tg_error(update, context):\n            log.error("TG handler error: %s", context.error)\n        tg_app.add_error_handler(_tg_error)\n\n        await tg_app.initialize()\n        await tg_app.bot.set_my_commands([\n            BotCommand("start", "歡迎"), BotCommand("status", "狀態"),\n            BotCommand("agents", "Agent 列表"), BotCommand("board", "看板"),\n            BotCommand("costs", "費用"), BotCommand("queue", "佇列"),\n            BotCommand("assign", "派工"), BotCommand("help", "說明"),\n        ])\n        await tg_app.start()\n        await tg_app.updater.start_polling(drop_pending_updates=True)\n\n        # 設定 reply callback\n        allowed_users = team_config.access.get("allowed_users", [])\n        chat_id = allowed_users[0] if allowed_users else 0\n\n        async def _tg_reply(agent_name: str, text: str):\n            if chat_id:\n                try:\n                    msg = text[:4000]\n                    await tg_app.bot.send_message(chat_id=chat_id, text=msg)\n                except Exception as e:\n                    log.warning("TG reply failed: %s", e)\n\n        tg_reply_fn = _tg_reply\n\n        # NotificationService\n        if chat_id:\n            from tg_ui.notifications import NotificationService\n            notify_service = NotificationService(tg_app, [chat_id])\n            notify_service.subscribe_to(bus)\n\n        log.info("Telegram Bot 已啟動")\n    else:\n        log.info("無 TELEGRAM_BOT_TOKEN，跳過 Bot")\n\n    # ── 5. Scheduler ──\n    try:\n        from ark_team_core.scheduler import Scheduler\n\n        async def _send_to(instance: str, message: str) -> bool:\n            agent = agents.get(instance)\n            if agent:\n                asyncio.create_task(agent.send(message))\n                return True\n            return False\n\n        scheduler = Scheduler(send_fn=_send_to)\n        count = scheduler.load_yaml("scheduler.yaml")\n        if count > 0:\n            scheduler.start()\n            log.info("Scheduler 已啟動 (%d jobs)", count)\n    except Exception as e:\n        log.info("Scheduler 未啟動: %s", e)\n\n    # ── 主迴圈 ──\n    log.info("✅ Ark Agent Platform 全部服務已啟動")\n    try:\n        while True:\n            await asyncio.sleep(30)\n    except (asyncio.CancelledError, KeyboardInterrupt):\n        pass\n    finally:\n        log.info("Shutting down...")\n        if tg_app:\n            await tg_app.updater.stop()\n            await tg_app.stop()\n            await tg_app.shutdown()\n        for proc in agents.values():\n            await proc.kill()\n        await bus.stop()\n        server.should_exit = True\n\n\nif __name__ == "__main__":\n    try:\n        asyncio.run(main())\n    except KeyboardInterrupt:\n        print("\\n平台已停止。")\n'


def write_start_py(output_dir: Path) -> None:
    (output_dir / "start.py").write_text(CONTENT, encoding="utf-8")
